:root {
  --radius: 0.75rem;

  /* Background: warm off-white with slight cream tone */
  --background: oklch(0.978 0.004 80);
  --foreground: oklch(0.18 0.02 255);

  /* Card: pure white for contrast */
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.18 0.02 255);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.18 0.02 255);

  /* Primary: deep navy-indigo */
  --primary: oklch(0.34 0.14 258);
  --primary-foreground: oklch(0.98 0 0);

  /* Secondary: soft slate */
  --secondary: oklch(0.94 0.005 255);
  --secondary-foreground: oklch(0.34 0.14 258);

  /* Muted */
  --muted: oklch(0.945 0.006 80);
  --muted-foreground: oklch(0.52 0.02 255);

  /* Accent: warm amber */
  --accent: oklch(0.96 0.025 85);
  --accent-foreground: oklch(0.38 0.12 55);

  --destructive: oklch(0.577 0.245 27.325);
  --border: oklch(0.9 0.008 255);
  --input: oklch(0.93 0.006 255);
  --ring: oklch(0.34 0.14 258);

  /* Charts */
  --chart-1: oklch(0.52 0.19 258);
  --chart-2: oklch(0.62 0.15 180);
  --chart-3: oklch(0.72 0.18 55);
  --chart-4: oklch(0.58 0.19 310);
  --chart-5: oklch(0.65 0.17 145);

  /* Sidebar: deep navy */
  --sidebar: oklch(0.22 0.06 258);
  --sidebar-foreground: oklch(0.95 0.01 255);
  --sidebar-primary: oklch(0.62 0.18 258);
  --sidebar-primary-foreground: oklch(0.98 0 0);
  --sidebar-accent: oklch(0.28 0.07 258);
  --sidebar-accent-foreground: oklch(0.95 0.01 255);
  --sidebar-border: oklch(0.30 0.07 258);
  --sidebar-ring: oklch(0.62 0.18 258);

  /* Custom design tokens */
  --gradient-hero: linear-gradient(135deg, oklch(0.34 0.14 258), oklch(0.42 0.18 275));
  --gradient-card: linear-gradient(160deg, oklch(1 0 0), oklch(0.97 0.01 258));
  --gradient-sidebar: linear-gradient(180deg, oklch(0.22 0.06 258), oklch(0.19 0.07 265));
  --gradient-amber: linear-gradient(135deg, oklch(0.72 0.18 55), oklch(0.78 0.16 75));
  --shadow-card: 0 1px 3px oklch(0.18 0.02 255 / 0.06), 0 4px 16px oklch(0.18 0.02 255 / 0.06);
  --shadow-hero: 0 8px 32px oklch(0.34 0.14 258 / 0.25);
  --transition-smooth: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);

  /* Fonts */
  --font-sans: 'Plus Jakarta Sans', sans-serif;
  --font-display: 'Space Grotesk', sans-serif;
}

