:root {
  --radius: 0.75rem;

  /* Background: warm off-white with slight cream tone */
  --background: oklch(0.978 0.004 80);
  --foreground: oklch(0.18 0.02 255);

  /* Card: pure white for contrast */
  --card: oklch(1 0 0);
